import React, { useState } from 'react';

const App = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [tasks, setTasks] = useState([]);
  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex flex-col items-center">
      <div className="bg-gray-600 p-4 w-full mb-4">
        <h1 className="text-lg text-gray-300">Task Management Dashboard</h1>
      </div>
      <div className="bg-gray-600 p-4 w-full mb-4">
        <input type="search" className="w-full p-2 text-gray-300" placeholder="Search tasks by title or description"/>
      </div>
      <button className="bg-gray-600 p-2 text-gray-300 mb-4" onClick={() => setDarkMode(!darkMode)}>Toggle dark mode</button>
      <div className="bg-gray-600 p-4 w-full mb-4">
        <h2 className="text-lg text-gray-300">Tasks</h2>
        <ul className="list-none mb-4">
          {tasks.map((task, index) => (
            <li key={index} className="bg-gray-600 p-2 mb-2">
              <h3 className="text-lg text-gray-300">{task.title}</h3>
              <p className="text-gray-300">{task.description}</p>
              <p className="text-gray-300">Status: {task.status}</p>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
};

export default App;
